# Usage: create_api_cache <api_id> <ttl> <api_caching_behavior> <type> <transit_encryption_enabled> <at_rest_encryption_enabled> <health_metrics_config>
create_api_cache() {
    aws appsync update-api-cache \
        --api-id "$API_ID" \
        --ttl "$TTL" \
        --api-caching-behavior "$API_CACHING_BEHAVIOR" \
        --type "$TYPE" \
